import request from 'supertest';
import { app, ensureRecipientsExist, registerAndLogin } from './test/helpers';

describe('Campaign business rules', () => {
  test('list campaigns supports mine and all scopes', async () => {
    const user1 = await registerAndLogin();
    const user2 = await registerAndLogin();
    await ensureRecipientsExist([
      { email: 'scope1@example.com', name: 'Scope1' },
      { email: 'scope2@example.com', name: 'Scope2' },
    ]);

    await request(app)
      .post('/campaigns')
      .set('Authorization', `Bearer ${user1.token}`)
      .send({
        name: 'U1 Campaign',
        subject: 'Hello U1',
        body: 'Body',
        recipients: [{ email: 'scope1@example.com', name: 'Scope1' }],
      })
      .expect(201);

    await request(app)
      .post('/campaigns')
      .set('Authorization', `Bearer ${user2.token}`)
      .send({
        name: 'U2 Campaign',
        subject: 'Hello U2',
        body: 'Body',
        recipients: [{ email: 'scope2@example.com', name: 'Scope2' }],
      })
      .expect(201);

    const mineRes = await request(app)
      .get('/campaigns?scope=mine')
      .set('Authorization', `Bearer ${user1.token}`)
      .expect(200);
    expect(mineRes.body.data).toHaveLength(1);

    const allRes = await request(app)
      .get('/campaigns?scope=all')
      .set('Authorization', `Bearer ${user1.token}`)
      .expect(200);
    expect(allRes.body.data).toHaveLength(2);
  });

  test('create campaign rejects recipients not existing in system', async () => {
    const { token } = await registerAndLogin();

    const response = await request(app)
      .post('/campaigns')
      .set('Authorization', `Bearer ${token}`)
      .send({
        name: 'C1',
        subject: 'Hello',
        body: 'Body',
        recipients: [{ email: 'missing@example.com', name: 'Missing' }],
      })
      .expect(422);

    expect(response.body.error.message).toBe('Some recipients do not exist in the system');
    expect(response.body.error.details).toEqual({
      missing_recipients: ['missing@example.com'],
    });
  });

  test('schedule must be a future timestamp', async () => {
    const { token } = await registerAndLogin();
    await ensureRecipientsExist([{ email: 'a@example.com', name: 'A' }]);

    const createRes = await request(app)
      .post('/campaigns')
      .set('Authorization', `Bearer ${token}`)
      .send({
        name: 'C1',
        subject: 'Hello',
        body: 'Body',
        recipients: [{ email: 'a@example.com', name: 'A' }],
      })
      .expect(201);

    const campaignId = createRes.body.data.id as number;

    await request(app)
      .post(`/campaigns/${campaignId}/schedule`)
      .set('Authorization', `Bearer ${token}`)
      .send({ scheduled_at: new Date(Date.now() - 60_000).toISOString() })
      .expect(422);
  });

  test('campaign can only be updated when status is draft', async () => {
    const { token } = await registerAndLogin();
    await ensureRecipientsExist([{ email: 'b@example.com', name: 'B' }]);

    const createRes = await request(app)
      .post('/campaigns')
      .set('Authorization', `Bearer ${token}`)
      .send({
        name: 'C1',
        subject: 'Hello',
        body: 'Body',
        recipients: [{ email: 'b@example.com', name: 'B' }],
      })
      .expect(201);

    const campaignId = createRes.body.data.id as number;

    await request(app)
      .post(`/campaigns/${campaignId}/schedule`)
      .set('Authorization', `Bearer ${token}`)
      .send({ scheduled_at: new Date(Date.now() + 60_000).toISOString() })
      .expect(200);

    await request(app)
      .patch(`/campaigns/${campaignId}`)
      .set('Authorization', `Bearer ${token}`)
      .send({ subject: 'Updated' })
      .expect(409);
  });

  test('send is one-way and stats returns rates and counts', async () => {
    const { token } = await registerAndLogin();
    await ensureRecipientsExist([
      { email: 'c1@example.com', name: 'C1' },
      { email: 'c2@example.com', name: 'C2' },
    ]);

    const createRes = await request(app)
      .post('/campaigns')
      .set('Authorization', `Bearer ${token}`)
      .send({
        name: 'C1',
        subject: 'Hello',
        body: 'Body',
        recipients: [
          { email: 'c1@example.com', name: 'C1' },
          { email: 'c2@example.com', name: 'C2' },
        ],
      })
      .expect(201);

    const campaignId = createRes.body.data.id as number;

    await request(app)
      .post(`/campaigns/${campaignId}/send`)
      .set('Authorization', `Bearer ${token}`)
      .send()
      .expect(200);

    // Sending again should fail
    await request(app)
      .post(`/campaigns/${campaignId}/send`)
      .set('Authorization', `Bearer ${token}`)
      .send()
      .expect(409);

    const statsRes = await request(app)
      .get(`/campaigns/${campaignId}/stats`)
      .set('Authorization', `Bearer ${token}`)
      .expect(200);

    expect(statsRes.body.data).toEqual({
      total: 2,
      sent: 2,
      failed: 0,
      opened: 0,
      open_rate: 0,
      send_rate: 1,
    });
  });
});

